{
  "name": "Animal Breed Identifier",
  "description": "An AI-powered application that identifies animal breeds from uploaded photos using the Gemini API. Features include user authentication, history tracking, and a comprehensive admin dashboard.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  USER = 'USER',
  ADMIN = 'ADMIN'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  createdAt: string;
}

export interface BreedResult {
  id: string;
  userId: string;
  imageUrl: string;
  animalType: string;
  breedName: string;
  confidence: number;
  description: string;
  similarBreeds: string[];
  timestamp: string;
}

export interface PredictionResponse {
  animalType: string;
  breedName: string;
  confidence: number;
  description: string;
  similarBreeds: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { PredictionResponse } from "../types";

const API_KEY = process.env.API_KEY || '';

export const identifyBreed = async (base64Image: string): Promise<PredictionResponse> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please ensure process.env.API_KEY is configured.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        {
          text: "Identify the animal in this image. Provide the animal type (e.g., Dog, Cat, Cow, Goat), the specific breed name, a confidence score between 0-100, a short 2-3 sentence description, and a list of 2-3 similar breeds.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          animalType: { type: Type.STRING },
          breedName: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          description: { type: Type.STRING },
          similarBreeds: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
        },
        required: ["animalType", "breedName", "confidence", "description", "similarBreeds"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI model.");

  try {
    return JSON.parse(text);
  } catch (error) {
    console.error("Failed to parse AI response:", text);
    throw new Error("Invalid response format from AI.");
  }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import Login from './components/Login';
import Signup from './components/Signup';
import Dashboard from './components/Dashboard';
import AdminDashboard from './components/AdminDashboard';
import LandingPage from './components/LandingPage';
import Navigation from './components/Navigation';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard' | 'admin'>('landing');

  useEffect(() => {
    const storedUser = localStorage.getItem('animal_id_user');
    if (storedUser) {
      const user = JSON.parse(storedUser);
      setCurrentUser(user);
      setView(user.role === UserRole.ADMIN ? 'admin' : 'dashboard');
    }
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('animal_id_user', JSON.stringify(user));
    setView(user.role === UserRole.ADMIN ? 'admin' : 'dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('animal_id_user');
    setView('landing');
  };

  const renderContent = () => {
    switch (view) {
      case 'landing':
        return <LandingPage onGetStarted={() => setView('login')} />;
      case 'login':
        return <Login onLogin={handleLogin} onSwitchToSignup={() => setView('signup')} onBack={() => setView('landing')} />;
      case 'signup':
        return <Signup onSignup={handleLogin} onSwitchToLogin={() => setView('login')} onBack={() => setView('landing')} />;
      case 'dashboard':
        return currentUser ? <Dashboard user={currentUser} /> : <Login onLogin={handleLogin} onSwitchToSignup={() => setView('signup')} onBack={() => setView('landing')} />;
      case 'admin':
        return currentUser?.role === UserRole.ADMIN ? <AdminDashboard user={currentUser} /> : <Dashboard user={currentUser!} />;
      default:
        return <LandingPage onGetStarted={() => setView('login')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navigation 
        user={currentUser} 
        onLogout={handleLogout} 
        setView={setView} 
        currentView={view}
      />
      <main className="flex-grow">
        {renderContent()}
      </main>
      <footer className="bg-white border-t border-gray-200 py-6 text-center text-gray-500 text-sm">
        <p>© 2024 Animal Breed Identifier. Powered by AI Intelligence.</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { User, UserRole } from '../types';

interface NavigationProps {
  user: User | null;
  onLogout: () => void;
  setView: (view: any) => void;
  currentView: string;
}

const Navigation: React.FC<NavigationProps> = ({ user, onLogout, setView, currentView }) => {
  return (
    <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <button onClick={() => setView('landing')} className="flex items-center space-x-2">
              <div className="bg-indigo-600 p-1.5 rounded-lg">
                <svg className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.5v15m7.5-7.5h-15" />
                </svg>
              </div>
              <span className="text-xl font-bold text-gray-900 tracking-tight">BreedFinder</span>
            </button>
          </div>

          <div className="flex items-center space-x-4">
            {user ? (
              <>
                <button 
                  onClick={() => setView(user.role === UserRole.ADMIN ? 'admin' : 'dashboard')}
                  className={`px-3 py-2 rounded-md text-sm font-medium ${currentView === 'dashboard' || currentView === 'admin' ? 'text-indigo-600 bg-indigo-50' : 'text-gray-600 hover:text-indigo-600'}`}
                >
                  Dashboard
                </button>
                <div className="h-6 w-px bg-gray-200 mx-2" />
                <div className="flex items-center space-x-3">
                  <span className="hidden md:block text-sm font-medium text-gray-700">{user.name}</span>
                  <button 
                    onClick={onLogout}
                    className="px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
                  >
                    Logout
                  </button>
                </div>
              </>
            ) : (
              <>
                <button 
                  onClick={() => setView('login')}
                  className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-indigo-600 transition-colors"
                >
                  Log In
                </button>
                <button 
                  onClick={() => setView('signup')}
                  className="px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-lg hover:bg-indigo-700 transition-colors"
                >
                  Sign Up
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navigation;

import React, { useState, useEffect } from 'react';
import { User, BreedResult } from '../types';
import { identifyBreed } from '../services/geminiService';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [history, setHistory] = useState<BreedResult[]>([]);
  const [currentResult, setCurrentResult] = useState<BreedResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const savedHistory = localStorage.getItem(`history_${user.id}`);
    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }
  }, [user.id]);

  const saveToHistory = (result: BreedResult) => {
    const updatedHistory = [result, ...history];
    setHistory(updatedHistory);
    localStorage.setItem(`history_${user.id}`, JSON.stringify(updatedHistory));

    // Also save to a global history for admin
    const globalHistory = JSON.parse(localStorage.getItem('admin_all_uploads') || '[]');
    localStorage.setItem('admin_all_uploads', JSON.stringify([result, ...globalHistory]));
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setError("File size should be less than 5MB");
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleIdentify = async () => {
    if (!selectedImage) return;

    setIsUploading(true);
    setError(null);
    setCurrentResult(null);

    try {
      const prediction = await identifyBreed(selectedImage);
      const newResult: BreedResult = {
        ...prediction,
        id: Math.random().toString(36).substr(2, 9),
        userId: user.id,
        imageUrl: selectedImage,
        timestamp: new Date().toISOString()
      };

      setCurrentResult(newResult);
      saveToHistory(newResult);
    } catch (err: any) {
      setError(err.message || "Failed to identify breed. Please try again.");
    } finally {
      setIsUploading(false);
    }
  };

  const resetUpload = () => {
    setSelectedImage(null);
    setCurrentResult(null);
    setError(null);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10">
        <h1 className="text-3xl font-bold text-gray-900">Welcome back, {user.name}</h1>
        <p className="text-gray-500 mt-2">Identify a new breed or browse your history below.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          {/* Upload Section */}
          <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="p-6 border-b border-gray-100">
              <h2 className="text-xl font-bold text-gray-900">New Identification</h2>
            </div>
            <div className="p-8">
              {!selectedImage ? (
                <div className="border-2 border-dashed border-gray-300 rounded-xl p-12 text-center hover:border-indigo-400 transition-colors cursor-pointer relative">
                  <input 
                    type="file" 
                    accept="image/png, image/jpeg" 
                    onChange={handleImageChange}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                  <div className="space-y-4">
                    <div className="mx-auto w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center">
                      <svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                      </svg>
                    </div>
                    <div>
                      <p className="text-lg font-medium text-gray-900">Click to upload or drag and drop</p>
                      <p className="text-sm text-gray-500">PNG, JPG up to 5MB</p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="relative group rounded-xl overflow-hidden max-h-[500px] flex justify-center bg-gray-50">
                    <img src={selectedImage} alt="Selected" className="max-h-full object-contain rounded-xl" />
                    {!currentResult && !isUploading && (
                      <button 
                        onClick={() => setSelectedImage(null)}
                        className="absolute top-4 right-4 bg-red-600 text-white p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                      </button>
                    )}
                  </div>

                  {error && (
                    <div className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-lg text-sm flex items-center">
                      <svg className="h-5 w-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                      {error}
                    </div>
                  )}

                  {!currentResult ? (
                    <button 
                      onClick={handleIdentify}
                      disabled={isUploading}
                      className="w-full py-4 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center space-x-2 shadow-lg transition-all"
                    >
                      {isUploading ? (
                        <>
                          <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                          </svg>
                          <span>Identifying Breed...</span>
                        </>
                      ) : (
                        <span>Identify Now</span>
                      )}
                    </button>
                  ) : (
                    <div className="space-y-6 animate-fadeIn">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100">
                          <p className="text-xs font-semibold text-indigo-600 uppercase">Breed Name</p>
                          <p className="text-2xl font-bold text-gray-900">{currentResult.breedName}</p>
                        </div>
                        <div className="bg-green-50 p-4 rounded-xl border border-green-100">
                          <p className="text-xs font-semibold text-green-600 uppercase">Confidence Score</p>
                          <p className="text-2xl font-bold text-gray-900">{currentResult.confidence}%</p>
                        </div>
                      </div>

                      <div className="bg-gray-50 p-6 rounded-xl border border-gray-100">
                        <p className="text-xs font-semibold text-gray-500 uppercase mb-2">Description</p>
                        <p className="text-gray-700 leading-relaxed">{currentResult.description}</p>
                      </div>

                      <div className="p-6 border border-gray-200 rounded-xl">
                        <p className="text-xs font-semibold text-gray-500 uppercase mb-3">Similar Breeds</p>
                        <div className="flex flex-wrap gap-2">
                          {currentResult.similarBreeds.map((breed, idx) => (
                            <span key={idx} className="px-3 py-1 bg-white border border-gray-300 rounded-full text-sm font-medium text-gray-600">
                              {breed}
                            </span>
                          ))}
                        </div>
                      </div>

                      <button 
                        onClick={resetUpload}
                        className="w-full py-4 border-2 border-indigo-600 text-indigo-600 font-bold rounded-xl hover:bg-indigo-50 transition-all"
                      >
                        Start New Identification
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </section>
        </div>

        {/* History Section */}
        <div className="space-y-6">
          <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col max-h-[800px]">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-bold text-gray-900">Your History</h2>
              <span className="text-xs font-medium text-gray-500 bg-gray-100 px-2.5 py-1 rounded-full">{history.length} Saved</span>
            </div>
            <div className="flex-grow overflow-y-auto p-4 space-y-4">
              {history.length === 0 ? (
                <div className="text-center py-20 px-6">
                  <div className="mx-auto w-12 h-12 text-gray-300 mb-4">
                    <svg fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                    </svg>
                  </div>
                  <p className="text-gray-500">No identifications yet. Your results will appear here.</p>
                </div>
              ) : (
                history.map((item) => (
                  <div key={item.id} className="group p-3 border border-gray-100 rounded-xl hover:border-indigo-200 hover:shadow-sm transition-all bg-white">
                    <div className="flex space-x-4">
                      <img src={item.imageUrl} alt={item.breedName} className="w-16 h-16 object-cover rounded-lg flex-shrink-0" />
                      <div className="flex-grow min-w-0">
                        <p className="font-bold text-gray-900 truncate">{item.breedName}</p>
                        <p className="text-xs text-gray-500 mb-1">{item.animalType}</p>
                        <div className="flex justify-between items-center">
                          <span className="text-xs font-semibold text-green-600 bg-green-50 px-2 py-0.5 rounded-full">{item.confidence}% match</span>
                          <span className="text-[10px] text-gray-400">{new Date(item.timestamp).toLocaleDateString()}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { User, UserRole, BreedResult } from '../types';

interface AdminDashboardProps {
  user: User;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [allUploads, setAllUploads] = useState<BreedResult[]>([]);
  const [activeTab, setActiveTab] = useState<'users' | 'uploads'>('users');

  useEffect(() => {
    // Load all registered users
    const storedUsers = JSON.parse(localStorage.getItem('animal_id_users') || '[]');
    setUsers(storedUsers);

    // Load all uploads across platform
    const storedUploads = JSON.parse(localStorage.getItem('admin_all_uploads') || '[]');
    setAllUploads(storedUploads);
  }, []);

  const deleteUpload = (id: string) => {
    const updatedUploads = allUploads.filter(u => u.id !== id);
    setAllUploads(updatedUploads);
    localStorage.setItem('admin_all_uploads', JSON.stringify(updatedUploads));
    // Note: In real app, we'd also need to delete from user's specific history
  };

  const deleteUser = (id: string) => {
    const updatedUsers = users.filter(u => u.id !== id);
    setUsers(updatedUsers);
    localStorage.setItem('animal_id_users', JSON.stringify(updatedUsers));
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 space-y-4 md:space-y-0">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Admin Control Panel</h1>
          <p className="text-gray-500 mt-2">Manage users and monitor identification activity.</p>
        </div>

        <div className="flex p-1 bg-gray-100 rounded-xl">
          <button 
            onClick={() => setActiveTab('users')}
            className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
          >
            Users ({users.length})
          </button>
          <button 
            onClick={() => setActiveTab('uploads')}
            className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'uploads' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
          >
            Recent Uploads ({allUploads.length})
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
        {activeTab === 'users' ? (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">User</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Email</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Role</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Joined</th>
                  <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {users.length === 0 ? (
                  <tr>
                    <td colSpan={5} className="px-6 py-10 text-center text-gray-500">No users found.</td>
                  </tr>
                ) : (
                  users.map((u) => (
                    <tr key={u.id} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="flex items-center">
                          <div className="h-10 w-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold">
                            {u.name.charAt(0)}
                          </div>
                          <div className="ml-4">
                            <div className="text-sm font-bold text-gray-900">{u.name}</div>
                            <div className="text-xs text-gray-500">ID: {u.id}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">{u.email}</td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`px-2.5 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 'bg-green-100 text-green-800'}`}>
                          {u.role}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {new Date(u.createdAt).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                        <button 
                          onClick={() => deleteUser(u.id)}
                          className="text-red-600 hover:text-red-900 font-bold ml-4 disabled:opacity-50"
                          disabled={u.id === user.id}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Preview</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Identified Breed</th>
                  <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Category</th>
