import { User, BreedResult, UserRole } from '../types';

const DB_NAME = 'AnimalBreedFinderDB';
const DB_VERSION = 1;

export class AnimalDB {
  private db: IDBDatabase | null = null;

  async init(): Promise<IDBDatabase> {
    if (this.db) return this.db;

    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onerror = () => reject(request.error);
      request.onsuccess = () => {
        this.db = request.result;
        resolve(request.result);
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;

        if (!db.objectStoreNames.contains('users')) {
          db.createObjectStore('users', { keyPath: 'id' });
          const userStore = db.transaction.objectStore('users');
          userStore.createIndex('email', 'email', { unique: true });
        }

        if (!db.objectStoreNames.contains('scans')) {
          db.createObjectStore('scans', { keyPath: 'id' });
          const scanStore = db.transaction.objectStore('scans');
          scanStore.createIndex('userId', 'userId', { unique: false });
          scanStore.createIndex('timestamp', 'timestamp', { unique: false });
        }
      };
    });
  }

  // --- User Operations ---

  async saveUser(user: User): Promise<void> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['users'], 'readwrite');
      const store = transaction.objectStore('users');
      const request = store.put(user);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async getUser(id: string): Promise<User | null> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['users'], 'readonly');
      const store = transaction.objectStore('users');
      const request = store.get(id);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  }

  async getUserByEmail(email: string): Promise<User | null> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['users'], 'readonly');
      const store = transaction.objectStore('users');
      const index = store.index('email');
      const request = index.get(email);
      request.onsuccess = () => resolve(request.result || null);
      request.onerror = () => reject(request.error);
    });
  }

  async getAllUsers(): Promise<User[]> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['users'], 'readonly');
      const store = transaction.objectStore('users');
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  // --- Scan Operations ---

  async saveScan(scan: BreedResult): Promise<void> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['scans'], 'readwrite');
      const store = transaction.objectStore('scans');
      const request = store.put(scan);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async getUserScans(userId: string): Promise<BreedResult[]> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['scans'], 'readonly');
      const store = transaction.objectStore('scans');
      const index = store.index('userId');
      const request = index.getAll(userId);
      request.onsuccess = () => {
        // Sort by timestamp descending
        const scans = request.result as BreedResult[];
        resolve(scans.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
      };
      request.onerror = () => reject(request.error);
    });
  }

  async getAllScans(): Promise<BreedResult[]> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['scans'], 'readonly');
      const store = transaction.objectStore('scans');
      const request = store.getAll();
      request.onsuccess = () => {
        const scans = request.result as BreedResult[];
        resolve(scans.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
      };
      request.onerror = () => reject(request.error);
    });
  }

  async deleteScan(id: string): Promise<void> {
    const db = await this.init();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(['scans'], 'readwrite');
      const store = transaction.objectStore('scans');
      const request = store.delete(id);
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  // --- Seeding ---
  async seedAdmin(): Promise<void> {
    const adminEmail = 'admin@breedfinder.com';
    const existing = await this.getUserByEmail(adminEmail);
    if (!existing) {
      await this.saveUser({
        id: 'admin-1',
        name: 'System Administrator',
        email: adminEmail,
        role: UserRole.ADMIN,
        createdAt: new Date().toISOString()
      });
    }
  }
}

export const db = new AnimalDB();

import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import Login from './components/Login';
import Signup from './components/Signup';
import Dashboard from './components/Dashboard';
import AdminDashboard from './components/AdminDashboard';
import LandingPage from './components/LandingPage';
import Navigation from './components/Navigation';
import { db } from './services/db';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard' | 'admin'>('landing');
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    const initApp = async () => {
      try {
        await db.init();
        await db.seedAdmin();

        const storedUserId = localStorage.getItem('animal_id_uid');
        if (storedUserId) {
          const user = await db.getUser(storedUserId);
          if (user) {
            setCurrentUser(user);
            setView(user.role === UserRole.ADMIN ? 'admin' : 'dashboard');
          }
        }
      } catch (err) {
        console.error("Failed to initialize database", err);
      } finally {
        setIsInitializing(false);
      }
    };

    initApp();
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('animal_id_uid', user.id);
    setView(user.role === UserRole.ADMIN ? 'admin' : 'dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('animal_id_uid');
    setView('landing');
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center space-y-4">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
          <p className="text-gray-500 font-medium">Waking up the database...</p>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (view) {
      case 'landing':
        return <LandingPage onGetStarted={() => setView('login')} />;
      case 'login':
        return <Login onLogin={handleLogin} onSwitchToSignup={() => setView('signup')} onBack={() => setView('landing')} />;
      case 'signup':
        return <Signup onSignup={handleLogin} onSwitchToLogin={() => setView('login')} onBack={() => setView('landing')} />;
      case 'dashboard':
        return currentUser ? <Dashboard user={currentUser} /> : <Login onLogin={handleLogin} onSwitchToSignup={() => setView('signup')} onBack={() => setView('landing')} />;
      case 'admin':
        return currentUser?.role === UserRole.ADMIN ? <AdminDashboard user={currentUser} /> : <Dashboard user={currentUser!} />;
      default:
        return <LandingPage onGetStarted={() => setView('login')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navigation 
        user={currentUser} 
        onLogout={handleLogout} 
        setView={setView} 
        currentView={view}
      />
      <main className="flex-grow">
        {renderContent()}
      </main>
      <footer className="bg-white border-t border-gray-200 py-6 text-center text-gray-500 text-sm">
        <p>© 2024 Animal Breed Identifier. Powered by AI Intelligence & DBMS.</p>
      </footer>
    </div>
  );
};

