import React, { useState, useEffect, useRef } from 'react';
import { User, BreedResult, HealthAnalysisResponse } from '../types';
import { 
  identifyBreed, 
  getBreedFacts, 
  generateBreedAudio, 
  decodeBase64, 
  decodeAudioData,
  generateSimilarBreedImage,
  detectAnimalDiseases
} from '../services/geminiService';
import { db } from '../services/db';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [isFetchingFacts, setIsFetchingFacts] = useState(false);
  const [isAnalyzingHealth, setIsAnalyzingHealth] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState<string | null>(null);
  const [isHistoryLoading, setIsHistoryLoading] = useState(true);

  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [history, setHistory] = useState<BreedResult[]>([]);
  const [currentResult, setCurrentResult] = useState<BreedResult | null>(null);
  const [healthAnalysis, setHealthAnalysis] = useState<HealthAnalysisResponse | null>(null);
  const [funFacts, setFunFacts] = useState<{text: string, sources: any[]} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [vizError, setVizError] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<{breed: string, url: string} | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const userScans = await db.getUserScans(user.id);
        setHistory(userScans);
      } catch (err) {
        console.error("Failed to fetch history", err);
      } finally {
        setIsHistoryLoading(false);
      }
    };
    fetchHistory();
    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, [user.id]);

  const saveToHistory = async (result: BreedResult) => {
    try {
      await db.saveScan(result);
      const updatedHistory = await db.getUserScans(user.id);
      setHistory(updatedHistory);
    } catch (err) {
      console.error("Failed to save scan to DBMS", err);
    }
  };

  const handleIdentify = async () => {
    if (!selectedImage) return;
    setIsUploading(true);
    setError(null);
    setCurrentResult(null);
    setFunFacts(null);
    setHealthAnalysis(null);
    setGeneratedImageUrl(null);
    setVizError(null);

    try {
      const prediction = await identifyBreed(selectedImage);
      const newResult: BreedResult = {
        ...prediction,
        id: Math.random().toString(36).substr(2, 9),
        userId: user.id,
        imageUrl: selectedImage,
        timestamp: new Date().toISOString()
      };
      setCurrentResult(newResult);
      await saveToHistory(newResult);
    } catch (err: any) {
      setError(err.message || "Failed to identify breed.");
    } finally {
      setIsUploading(false);
    }
  };

  const handleHealthCheck = async () => {
    if (!selectedImage || !currentResult) return;
    setIsAnalyzingHealth(true);
    try {
      const analysis = await detectAnimalDiseases(selectedImage, currentResult.animalType);
      setHealthAnalysis(analysis);

      const updatedResult = { ...currentResult, healthAnalysis: analysis };
      setCurrentResult(updatedResult);
      await saveToHistory(updatedResult);
    } catch (err: any) {
      console.error(err);
      setError("Health analysis failed. Please try again.");
    } finally {
      setIsAnalyzingHealth(false);
    }
  };

  const handleListen = async () => {
    if (!currentResult || isPlayingAudio) return;
    setIsPlayingAudio(true);
    try {
      if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const base64 = await generateBreedAudio(currentResult.description);
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioContextRef.current);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlayingAudio(false);
      source.start();
    } catch (err) {
      console.error(err);
      setIsPlayingAudio(false);
    }
  };

  const handleGetFacts = async () => {
    if (!currentResult) return;
    setIsFetchingFacts(true);
    try {
      const facts = await getBreedFacts(currentResult.breedName);
      setFunFacts(facts);
    } catch (err) {
      console.error(err);
    } finally {
      setIsFetchingFacts(false);
    }
  };

  const handleVisualize = async (breed: string) => {
    setIsGeneratingImage(breed);
    setVizError(null);
    try {
      const url = await generateSimilarBreedImage(breed);
      setGeneratedImageUrl({ breed, url });
    } catch (err: any) {
      console.error(err);
      setVizError(err.message || "Could not generate image for this breed.");
    } finally {
      setIsGeneratingImage(null);
    }
  };

  const selectHistoryItem = (item: BreedResult) => {
    setSelectedImage(item.imageUrl);
    setCurrentResult(item);
    setHealthAnalysis(item.healthAnalysis || null);
    setFunFacts(null);
    setVizError(null);
    setGeneratedImageUrl(null);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10 animate-fade-in">
        <h1 className="text-3xl font-bold text-gray-900 tracking-tight">AI Breed Discovery & Health</h1>
        <p className="text-gray-500 mt-2">Identify animal breeds, check visible health status, and listen to insights (DBMS Powered).</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white rounded-3xl shadow-xl shadow-indigo-50 border border-gray-100 overflow-hidden">
            <div className="p-8">
              {!selectedImage ? (
                <div className="border-2 border-dashed border-indigo-200 bg-indigo-50/30 rounded-2xl p-16 text-center hover:border-indigo-400 transition-all cursor-pointer relative group">
                  <input type="file" accept="image/*" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onloadend = () => setSelectedImage(reader.result as string);
                      reader.readAsDataURL(file);
                    }
                  }} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                  <div className="space-y-4">
                    <div className="mx-auto w-20 h-20 bg-white text-indigo-600 rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                      <svg className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                      </svg>
                    </div>
                    <div>
                      <p className="text-xl font-bold text-gray-900">Upload Animal Photo</p>
                      <p className="text-sm text-gray-500">Tap to browse or drag & drop</p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="space-y-8">
                  <div className="relative group rounded-3xl overflow-hidden shadow-2xl bg-gray-900 aspect-video flex items-center justify-center">
                    <img src={selectedImage} alt="Selected" className="max-h-full max-w-full object-contain" />
                    {!currentResult && !isUploading && (
                      <button onClick={() => setSelectedImage(null)} className="absolute top-6 right-6 bg-black/50 backdrop-blur-md text-white p-3 rounded-full hover:bg-red-600 transition-all">
                        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    )}
                  </div>

                  {error && (
                    <div className="bg-red-50 border border-red-100 p-4 rounded-2xl text-red-600 text-sm flex items-center animate-fade-in">
                      <svg className="h-5 w-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      {error}
                    </div>
                  )}

                  {!currentResult ? (
                    <button onClick={handleIdentify} disabled={isUploading} className="w-full py-5 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center space-x-3 shadow-xl transition-all hover:translate-y-[-2px]">
                      {isUploading ? (
                        <><div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white"></div><span>Analyzing Features...</span></>
                      ) : (
                        <span>Identify Breed</span>
                      )}
