                  ) : (
                    <div className="animate-fade-in space-y-8">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="bg-gradient-to-br from-indigo-500 to-indigo-700 p-6 rounded-3xl text-white shadow-lg">
                          <p className="text-xs font-bold uppercase opacity-80 mb-1">Identified Breed</p>
                          <p className="text-3xl font-black">{currentResult.breedName}</p>
                          <p className="mt-2 text-sm bg-white/20 inline-block px-3 py-1 rounded-full">{currentResult.animalType}</p>
                        </div>
                        <div className="bg-white border-2 border-gray-100 p-6 rounded-3xl shadow-sm flex flex-col justify-center">
                          <p className="text-xs font-bold text-gray-400 uppercase mb-1">AI Confidence</p>
                          <div className="flex items-end space-x-2">
                            <span className="text-4xl font-black text-indigo-600">{currentResult.confidence}%</span>
                            <div className="flex-grow h-2 bg-gray-100 rounded-full mb-3 overflow-hidden">
                              <div className="h-full bg-indigo-500 rounded-full" style={{width: `${currentResult.confidence}%`}}></div>
                            </div>
                          </div>
                        </div>
                      </div>

                      <div className="bg-gray-50 p-8 rounded-3xl border border-gray-100 relative">
                        <div className="flex justify-between items-start mb-4">
                          <p className="text-xs font-bold text-gray-400 uppercase">Breed Insight</p>
                          <button 
                            onClick={handleListen} 
                            disabled={isPlayingAudio}
                            className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${isPlayingAudio ? 'bg-indigo-600 text-white animate-pulse' : 'bg-white text-indigo-600 shadow-md hover:bg-indigo-50'}`}
                          >
                            <svg className="h-4 w-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
                            <span>{isPlayingAudio ? 'AI is speaking...' : 'Listen to AI'}</span>
                          </button>
                        </div>
                        <p className="text-gray-700 text-lg leading-relaxed italic">"{currentResult.description}"</p>
                      </div>

                      {/* Health Scan Section */}
                      <div className="p-8 border-2 border-red-50 rounded-3xl bg-red-50/20">
                         <div className="flex items-center justify-between mb-6">
                            <div>
                               <h3 className="text-xl font-bold text-gray-900 flex items-center">
                                  <svg className="h-6 w-6 text-red-500 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
