                                  disabled={isAnalyzingHealth}
                                  className="px-6 py-2 bg-red-600 text-white text-sm font-bold rounded-xl hover:bg-red-700 transition-all flex items-center"
                               >
                                  {isAnalyzingHealth ? (
                                     <>
                                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                                        Scanning...
                                     </>
                                  ) : "Perform Health Check"}
                               </button>
                            )}
                         </div>

                         {healthAnalysis && (
                            <div className="space-y-6 animate-fade-in">
                               <div className={`p-4 rounded-2xl flex items-center space-x-3 ${healthAnalysis.isHealthy ? 'bg-green-100 text-green-800' : 'bg-amber-100 text-amber-800'}`}>
                                  {healthAnalysis.isHealthy ? (
                                     <svg className="h-6 w-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                                  ) : (
                                     <svg className="h-6 w-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                  )}
                                  <span className="font-bold">{healthAnalysis.isHealthy ? "No visible issues found." : "Potential issues detected."}</span>
                               </div>

                               <p className="text-sm text-gray-700 leading-relaxed bg-white/50 p-4 rounded-xl border border-red-50">{healthAnalysis.summary}</p>

                               {!healthAnalysis.isHealthy && healthAnalysis.potentialIssues.length > 0 && (
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                     {healthAnalysis.potentialIssues.map((issue, idx) => (
                                        <div key={idx} className="bg-white p-4 rounded-2xl border border-red-100 shadow-sm relative overflow-hidden">
                                           <div className={`absolute top-0 right-0 px-3 py-1 text-[10px] font-bold rounded-bl-xl ${issue.severity === 'High' ? 'bg-red-600 text-white' : issue.severity === 'Medium' ? 'bg-amber-500 text-white' : 'bg-blue-500 text-white'}`}>
                                              {issue.severity} Severity
                                           </div>
                                           <h4 className="font-bold text-gray-900 mb-1 pr-16">{issue.issue}</h4>
                                           <p className="text-xs text-gray-600 mb-3">{issue.description}</p>
                                           <div className="pt-3 border-t border-gray-50 flex items-start space-x-2">
                                              <svg className="h-4 w-4 text-indigo-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                              <p className="text-[10px] font-bold text-indigo-600 italic uppercase">Advice: {issue.recommendedAction}</p>
                                           </div>
                                        </div>
                                     ))}
                                  </div>
                               )}

                               <div className="bg-gray-900 text-white p-4 rounded-xl text-[10px] font-medium opacity-80 leading-tight">
                                  ⚠️ DISCLAIMER: This health scan is powered by AI and based on visual data only. It is not a clinical diagnosis. If your animal shows any signs of distress, pain, or illness, consult a licensed veterinarian immediately.
                               </div>
                            </div>
                         )}
                      </div>

                      <div className="space-y-4">
                        <div className="flex items-center justify-between">
                          <h3 className="font-bold text-gray-900">Similar Breeds to Explore</h3>
                        </div>
                        {vizError && (
                          <div className="text-xs text-red-500 bg-red-50 p-2 rounded-lg border border-red-100 flex items-center">
                            <svg className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            {vizError}
                          </div>
                        )}
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                          {currentResult.similarBreeds.map((breed, idx) => (
                            <div key={idx} className="group bg-white p-4 rounded-2xl border border-gray-100 hover:border-indigo-200 transition-all shadow-sm">
                              <p className="font-bold text-gray-800 mb-3">{breed}</p>
                              <button 
                                onClick={() => handleVisualize(breed)}
                                disabled={isGeneratingImage === breed}
                                className="w-full text-xs font-bold py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 disabled:opacity-50 transition-colors"
                              >
                                {isGeneratingImage === breed ? 'Visualizing...' : 'Visualize with AI'}
                              </button>
                            </div>
                          ))}
                        </div>
                      </div>

                      {/* Fact Grounding Section */}
                      <div className="pt-6 border-t border-gray-100">
                        {!funFacts ? (
                          <button 
                            onClick={handleGetFacts} 
                            disabled={isFetchingFacts}
                            className="flex items-center space-x-2 text-indigo-600 font-bold hover:text-indigo-800 transition-colors"
                          >
                            {isFetchingFacts ? (
                              <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-indigo-600"></div>
                            ) : (
                              <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            )}
                            <span>Search Grounded Fun Facts</span>
                          </button>
                        ) : (
                          <div className="bg-indigo-50/50 p-6 rounded-3xl border border-indigo-100 animate-fade-in">
                            <h4 className="font-bold text-indigo-900 mb-4 flex items-center">
                              <svg className="h-5 w-5 mr-2" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-11a1 1 0 10-2 0v2H7a1 1 0 100 2h2v2a1 1 0 102 0v-2h2a1 1 0 100-2h-2V7z" clipRule="evenodd" /></svg>
                              Grounded Insights
                            </h4>
                            <div className="text-gray-700 text-sm leading-relaxed space-y-4 whitespace-pre-line">
                              {funFacts.text}
                            </div>
                            {funFacts.sources.length > 0 && (
                              <div className="mt-6 flex flex-wrap gap-2">
                                <p className="text-[10px] font-bold text-indigo-400 uppercase w-full">Verified Sources:</p>
                                {funFacts.sources.map((src: any, idx: number) => (
                                  <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-white border border-indigo-100 px-3 py-1 rounded-full text-indigo-600 hover:bg-indigo-600 hover:text-white transition-colors">
                                    {src.title || 'Search Link'}
                                  </a>
                                ))}
                              </div>
                            )}
                          </div>
                        )}
                      </div>

                      <button onClick={() => { setSelectedImage(null); setCurrentResult(null); setFunFacts(null); setHealthAnalysis(null); setVizError(null); }} className="w-full py-4 border-2 border-gray-200 text-gray-500 font-bold rounded-2xl hover:bg-gray-50 transition-all">
                        Discard & New Scan
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </section>
        </div>

        <div className="space-y-6">
          <section className="bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden flex flex-col max-h-[800px]">
            <div className="p-6 border-b border-gray-50 flex justify-between items-center">
              <h2 className="text-lg font-bold text-gray-900">Recent Scans</h2>
              <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">{history.length} Saved</span>
            </div>
            <div className="flex-grow overflow-y-auto p-4 space-y-3 custom-scrollbar">
              {isHistoryLoading ? (
                 <div className="flex flex-col items-center justify-center h-full space-y-2 py-20">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                    <p className="text-xs text-gray-400">Loading catalog...</p>
                 </div>
              ) : history.length === 0 ? (
                <div className="text-center py-20 px-6 opacity-40 grayscale">
                  <svg className="mx-auto h-12 w-12 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                  <p className="mt-4 text-xs font-medium">Your animal catalog will appear here</p>
                </div>
              ) : (
                history.map((item) => (
                  <button key={item.id} onClick={() => selectHistoryItem(item)} className="w-full text-left group p-3 border border-transparent hover:border-indigo-100 rounded-2xl hover:bg-indigo-50/30 transition-all bg-white relative">
                    <div className="flex space-x-3">
                      <img src={item.imageUrl} alt={item.breedName} className="w-14 h-14 object-cover rounded-xl flex-shrink-0 shadow-sm" />
                      <div className="flex-grow min-w-0 flex flex-col justify-center">
                        <div className="flex items-center space-x-2">
                          <p className="font-bold text-gray-900 truncate text-sm">{item.breedName}</p>
                          {item.healthAnalysis && (
                            <span title="Health Report Attached" className="flex-shrink-0">
                               <svg className={`h-3 w-3 ${item.healthAnalysis.isHealthy ? 'text-green-500' : 'text-red-500'}`} fill="currentColor" viewBox="0 0 20 20">
                                  <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                               </svg>
                            </span>
                          )}
                        </div>
                        <p className="text-[10px] text-gray-400 font-medium">{item.animalType} • {new Date(item.timestamp).toLocaleDateString()}</p>
                      </div>
                    </div>
                  </button>
                ))
              )}
            </div>
          </section>
        </div>
      </div>

      {/* Modal for Generated Image */}
      {generatedImageUrl && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-3xl max-w-lg w-full overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h3 className="font-bold text-gray-900">AI Visualized: {generatedImageUrl.breed}</h3>
              <button onClick={() => setGeneratedImageUrl(null)} className="text-gray-400 hover:text-red-500">
                <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <div className="p-2">
              <img src={generatedImageUrl.url} alt={generatedImageUrl.breed} className="w-full h-auto rounded-2xl" />
            </div>
            <div className="p-6 bg-gray-50 flex justify-end">
              <button onClick={() => setGeneratedImageUrl(null)} className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl text-sm hover:bg-indigo-700 transition-colors shadow-lg">Close View</button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { User, UserRole, BreedResult } from '../types';
import { db } from '../services/db';

interface AdminDashboardProps {
  user: User;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [allUploads, setAllUploads] = useState<BreedResult[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'users' | 'uploads'>('users');

  useEffect(() => {
    const fetchAdminData = async () => {
      try {
        const [allUsers, allScans] = await Promise.all([
          db.getAllUsers(),
          db.getAllScans()
        ]);
        setUsers(allUsers);
        setAllUploads(allScans);
      } catch (err) {
        console.error("Failed to fetch admin data", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchAdminData();
  }, []);

  const getStats = () => {
    const breeds = allUploads.map(u => u.breedName);
    const mostCommon = breeds.length > 0 ? [...breeds].sort((a,b) => breeds.filter(v => v===a).length - breeds.filter(v => v===b).length).pop() : 'N/A';
    return {
      totalUsers: users.length,
      totalScans: allUploads.length,
      mostCommon,
      avgConfidence: allUploads.length > 0 ? (allUploads.reduce((acc, u) => acc + u.confidence, 0) / allUploads.length).toFixed(1) : '0'
    };
  };

  const handleDeleteScan = async (id: string) => {
    if (!window.confirm("Purge this record from DBMS?")) return;
    try {
      await db.deleteScan(id);
      setAllUploads(prev => prev.filter(s => s.id !== id));
    } catch (err) {
      alert("Failed to delete scan.");
    }
  };

  if (isLoading) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-20 text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto"></div>
        <p className="mt-4 text-gray-500">Compiling statistics...</p>
      </div>
    );
  }

  const stats = getStats();

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10">
        <h1 className="text-3xl font-black text-gray-900 tracking-tight">Admin Intelligence</h1>
        <p className="text-gray-500 mt-2">Platform performance and user governance (DBMS Powered).</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
        <StatCard label="Total Community" value={stats.totalUsers} color="indigo" />
        <StatCard label="Successful Scans" value={stats.totalScans} color="green" />
        <StatCard label="Avg. Confidence" value={`${stats.avgConfidence}%`} color="blue" />
        <StatCard label="Top Breed" value={stats.mostCommon} color="purple" />
      </div>

      <div className="flex space-x-2 p-1 bg-gray-100 rounded-2xl w-fit mb-8">
        <button onClick={() => setActiveTab('users')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>User Directory</button>
        <button onClick={() => setActiveTab('uploads')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${activeTab === 'uploads' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>Scan Activity</button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        {activeTab === 'users' ? (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-100">
              <thead className="bg-gray-50/50">
                <tr>
                  <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Identity</th>
                  <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Credentials</th>
                  <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Privileges</th>
                  <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Enrolled</th>
                  <th className="px-6 py-4 text-right text-[10px] font-bold text-gray-400 uppercase tracking-widest">Management</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {users.map((u) => (
                  <tr key={u.id} className="hover:bg-gray-50/50 transition-colors">
                    <td className="px-6 py-5 whitespace-nowrap">
                      <div className="flex items-center">
