import { GoogleGenAI, Type, Modality } from "@google/genai";
import { PredictionResponse, HealthAnalysisResponse } from "../types";

// Initialize GoogleGenAI right before making an API call to ensure it uses the current process.env.API_KEY
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const identifyBreed = async (base64Image: string): Promise<PredictionResponse> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        {
          text: "Identify the animal in this image. Provide the animal type, specific breed name, confidence score (0-100), a short 2-3 sentence description, and a list of 2-3 similar breeds.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          animalType: { type: Type.STRING },
          breedName: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          description: { type: Type.STRING },
          similarBreeds: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
        },
        required: ["animalType", "breedName", "confidence", "description", "similarBreeds"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI failed to return identification results. Please try another image.");
  return JSON.parse(text);
};

export const detectAnimalDiseases = async (base64Image: string, animalType: string): Promise<HealthAnalysisResponse> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        {
          text: `Perform a preliminary visual health check on this ${animalType}. Look for visible signs of skin conditions, eye discharge, dental issues, injuries, or external parasites. Return a JSON report indicating if the animal appears healthy and a list of potential issues if found.`,
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isHealthy: { type: Type.BOOLEAN },
          summary: { type: Type.STRING },
          potentialIssues: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                issue: { type: Type.STRING },
                severity: { 
                  type: Type.STRING,
                  enum: ['Low', 'Medium', 'High']
                },
                description: { type: Type.STRING },
                recommendedAction: { type: Type.STRING }
              },
              required: ["issue", "severity", "description", "recommendedAction"]
            }
          }
        },
        required: ["isHealthy", "summary", "potentialIssues"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Health analysis failed.");
  return JSON.parse(text);
};

export const getBreedFacts = async (breedName: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Tell me 3 amazing and unique fun facts about the ${breedName} breed. Include recent news if any.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  return {
    text: response.text,
    sources: sources.map((s: any) => s.web).filter(Boolean)
  };
};

export const generateSimilarBreedImage = async (breedName: string) => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A professional, high-quality studio portrait of a ${breedName}. Focus on realistic features, beautiful studio lighting, and a clean, complementary background.` }],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    if (!response.candidates || response.candidates.length === 0) {
      throw new Error("No candidates returned from the image model.");
    }

    const parts = response.candidates[0].content.parts;
    for (const part of parts) {
      if (part.inlineData && part.inlineData.data) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    const textPart = parts.find(p => p.text);
    if (textPart && textPart.text) {
      throw new Error(`AI Refusal: ${textPart.text}`);
    }

    throw new Error("The AI model did not include an image in its response.");
  } catch (err: any) {
    console.error("Image Generation Failure:", err);
    throw new Error(err.message || "Failed to generate image.");
  }
};

export const generateBreedAudio = async (text: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Speak cheerfully and professionally: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio data returned from TTS model.");
  return base64Audio;
};

// Manually implement base64 decoding for TypedArray conversion
export function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Decodes raw PCM audio bytes returned by the Gemini TTS model
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useEffect, useRef } from 'react';
import { User, BreedResult, HealthAnalysisResponse } from '../types';
import { 
  identifyBreed, 
  getBreedFacts, 
  generateBreedAudio, 
  decodeBase64, 
  decodeAudioData,
  generateSimilarBreedImage,
  detectAnimalDiseases
} from '../services/geminiService';
import { db } from '../services/db';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [isFetchingFacts, setIsFetchingFacts] = useState(false);
  const [isAnalyzingHealth, setIsAnalyzingHealth] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState<string | null>(null);
  const [isHistoryLoading, setIsHistoryLoading] = useState(true);

  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [history, setHistory] = useState<BreedResult[]>([]);
  const [currentResult, setCurrentResult] = useState<BreedResult | null>(null);
  const [healthAnalysis, setHealthAnalysis] = useState<HealthAnalysisResponse | null>(null);
  const [funFacts, setFunFacts] = useState<{text: string, sources: any[]} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [vizError, setVizError] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<{breed: string, url: string} | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const userScans = await db.getUserScans(user.id);
        setHistory(userScans);
      } catch (err) {
        console.error("Failed to fetch history", err);
      } finally {
        setIsHistoryLoading(false);
      }
    };
    fetchHistory();
    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, [user.id]);

  const saveToHistory = async (result: BreedResult) => {
    try {
      await db.saveScan(result);
      const updatedHistory = await db.getUserScans(user.id);
      setHistory(updatedHistory);
    } catch (err) {
      console.error("Failed to save scan to DBMS", err);
    }
  };

  const handleIdentify = async () => {
    if (!selectedImage) return;
    setIsUploading(true);
    setError(null);
    setCurrentResult(null);
    setFunFacts(null);
    setHealthAnalysis(null);
    setGeneratedImageUrl(null);
    setVizError(null);

    try {
      const prediction = await identifyBreed(selectedImage);
      const newResult: BreedResult = {
        ...prediction,
        id: Math.random().toString(36).substr(2, 9),
        userId: user.id,
        imageUrl: selectedImage,
        timestamp: new Date().toISOString()
      };
      setCurrentResult(newResult);
      await saveToHistory(newResult);
    } catch (err: any) {
      setError(err.message || "Failed to identify breed.");
    } finally {
      setIsUploading(false);
    }
  };

  const handleHealthCheck = async () => {
    if (!selectedImage || !currentResult) return;
    setIsAnalyzingHealth(true);
    try {
      const analysis = await detectAnimalDiseases(selectedImage, currentResult.animalType);
      setHealthAnalysis(analysis);

      const updatedResult = { ...currentResult, healthAnalysis: analysis };
      setCurrentResult(updatedResult);
      await saveToHistory(updatedResult);
    } catch (err: any) {
      console.error(err);
      setError("Health analysis failed. Please try again.");
    } finally {
      setIsAnalyzingHealth(false);
    }
  };

  const handleListen = async () => {
    if (!currentResult || isPlayingAudio) return;
    setIsPlayingAudio(true);
    try {
      // AudioContext should be initialized with 24000 sample rate for Gemini TTS compatibility
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
          sampleRate: 24000
        });
      }
      const base64 = await generateBreedAudio(currentResult.description);
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioContextRef.current);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlayingAudio(false);
      source.start();
    } catch (err) {
      console.error(err);
      setIsPlayingAudio(false);
    }
  };

  const handleGetFacts = async () => {
    if (!currentResult) return;
    setIsFetchingFacts(true);
    try {
      const facts = await getBreedFacts(currentResult.breedName);
      setFunFacts(facts);
    } catch (err) {
      console.error(err);
    } finally {
      setIsFetchingFacts(false);
    }
  };

  const handleVisualize = async (breed: string) => {
    setIsGeneratingImage(breed);
    setVizError(null);
    try {
      const url = await generateSimilarBreedImage(breed);
      setGeneratedImageUrl({ breed, url });
    } catch (err: any) {
      console.error(err);
      setVizError(err.message || "Could not generate image for this breed.");
    } finally {
      setIsGeneratingImage(null);
    }
  };

  const selectHistoryItem = (item: BreedResult) => {
    setSelectedImage(item.imageUrl);
    setCurrentResult(item);
    setHealthAnalysis(item.healthAnalysis || null);
    setFunFacts(null);
    setVizError(null);
    setGeneratedImageUrl(null);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10 animate-fade-in">
        <h1 className="text-3xl font-bold text-gray-900 tracking-tight">AI Breed Discovery & Health</h1>
        <p className="text-gray-500 mt-2">Identify animal breeds, check visible health status, and listen to insights (DBMS Powered).</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white rounded-3xl shadow-xl shadow-indigo-50 border border-gray-100 overflow-hidden">
            <div className="p-8">
              {!selectedImage ? (
                <div className="border-2 border-dashed border-indigo-200 bg-indigo-50/30 rounded-2xl p-16 text-center hover:border-indigo-400 transition-all cursor-pointer relative group">
                  <input type="file" accept="image/*" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onloadend = () => setSelectedImage(reader.result as string);
                      reader.readAsDataURL(file);
                    }
                  }} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                  <div className="space-y-4">
                    <div className="mx-auto w-20 h-20 bg-white text-indigo-600 rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                      <svg className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                      </svg>
                    </div>
                    <div>
                      <p className="text-xl font-bold text-gray-900">Upload Animal Photo</p>
                      <p className="text-sm text-gray-500">Tap to browse or drag & drop</p>
                    </div>
                  </div>
                </div>
              ) : (
                <div className="space-y-8">
                  <div className="relative group rounded-3xl overflow-hidden shadow-2xl bg-gray-900 aspect-video flex items-center justify-center">
                    <img src={selectedImage} alt="Selected" className="max-h-full max-w-full object-contain" />
                    {!currentResult && !isUploading && (
                      <button onClick={() => setSelectedImage(null)} className="absolute top-6 right-6 bg-black/50 backdrop-blur-md text-white p-3 rounded-full hover:bg-red-600 transition-all">
                        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    )}
                  </div>

                  {error && (
                    <div className="bg-red-50 border border-red-100 p-4 rounded-2xl text-red-600 text-sm flex items-center animate-fade-in">
                      <svg className="h-5 w-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      {error}
                    </div>
                  )}

                  {!currentResult ? (
                    <button onClick={handleIdentify} disabled={isUploading} className="w-full py-5 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center space-x-3 shadow-xl transition-all hover:translate-y-[-2px]">
                      {isUploading ? (
                        <><div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white"></div><span>Analyzing Features...</span></>
                      ) : (
                        <span>Identify Breed</span>
                      )}
                    </button>
                  ) : (
                    <div className="animate-fade-in space-y-8">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="bg-gradient-to-br from-indigo-500 to-indigo-700 p-6 rounded-3xl text-white shadow-lg">
                          <p className="text-xs font-bold uppercase opacity-80 mb-1">Identified Breed</p>
                          <p className="text-3xl font-black">{currentResult.breedName}</p>
                          <p className="mt-2 text-sm bg-white/20 inline-block px-3 py-1 rounded-full">{currentResult.animalType}</p>
                        </div>
                        <div className="bg-white border-2 border-gray-100 p-6 rounded-3xl shadow-sm flex flex-col justify-center">
                          <p className="text-xs font-bold text-gray-400 uppercase mb-1">AI Confidence</p>
                          <div className="flex items-end space-x-2">
                            <span className="text-4xl font-black text-indigo-600">{currentResult.confidence}%</span>
                            <div className="flex-grow h-2 bg-gray-100 rounded-full mb-3 overflow-hidden">
                              <div className="h-full bg-indigo-500 rounded-full" style={{width: `${currentResult.confidence}%`}}></div>
                            </div>
                          </div>
                        </div>
                      </div>

                      <div className="bg-gray-50 p-8 rounded-3xl border border-gray-100 relative">
                        <div className="flex justify-between items-start mb-4">
                          <p className="text-xs font-bold text-gray-400 uppercase">Breed Insight</p>
                          <button 
                            onClick={handleListen} 
                            disabled={isPlayingAudio}
                            className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${isPlayingAudio ? 'bg-indigo-600 text-white animate-pulse' : 'bg-white text-indigo-600 shadow-md hover:bg-indigo-50'}`}
                          >
                            <svg className="h-4 w-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.984 5.984 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.983 3.983 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" /></svg>
                            <span>{isPlayingAudio ? 'AI is speaking...' : 'Listen to AI'}</span>
                          </button>
                        </div>
                        <p className="text-gray-700 text-lg leading-relaxed italic">"{currentResult.description}"</p>
                      </div>

                      {/* Health Scan Section */}
                      <div className="p-8 border-2 border-red-50 rounded-3xl bg-red-50/20">
                         <div className="flex items-center justify-between mb-6">
                            <div>
                               <h3 className="text-xl font-bold text-gray-900 flex items-center">
                                  <svg className="h-6 w-6 text-red-500 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                                  Visual Health Scan
                               </h3>
                               <p className="text-sm text-gray-500">Analyze visible symptoms or health issues.</p>
                            </div>
                            {!healthAnalysis && (
                               <button 
                                  onClick={handleHealthCheck} 
                                  disabled={isAnalyzingHealth}
                                  className="px-6 py-2 bg-red-600 text-white text-sm font-bold rounded-xl hover:bg-red-700 transition-all flex items-center"
                               >
                                  {isAnalyzingHealth ? (
                                     <>
                                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                                        Scanning...
                                     </>
                                  ) : "Perform Health Check"}
                               </button>
                            )}
                         </div>

                         {healthAnalysis && (
                            <div className="space-y-6 animate-fade-in">
                               <div className={`p-4 rounded-2xl flex items-center space-x-3 ${healthAnalysis.isHealthy ? 'bg-green-100 text-green-800' : 'bg-amber-100 text-amber-800'}`}>
                                  {healthAnalysis.isHealthy ? (
                                     <svg className="h-6 w-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                                  ) : (
                                     <svg className="h-6 w-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                  )}
                                  <span className="font-bold">{healthAnalysis.isHealthy ? "No visible issues found." : "Potential issues detected."}</span>
                               </div>

                               <p className="text-sm text-gray-700 leading-relaxed bg-white/50 p-4 rounded-xl border border-red-50">{healthAnalysis.summary}</p>

                               {!healthAnalysis.isHealthy && healthAnalysis.potentialIssues.length > 0 && (
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                     {healthAnalysis.potentialIssues.map((issue, idx) => (
                                        <div key={idx} className="bg-white p-4 rounded-2xl border border-red-100 shadow-sm relative overflow-hidden">
                                           <div className={`absolute top-0 right-0 px-3 py-1 text-[10px] font-bold rounded-bl-xl ${issue.severity === 'High' ? 'bg-red-600 text-white' : issue.severity === 'Medium' ? 'bg-amber-500 text-white' : 'bg-blue-500 text-white'}`}>
                                              {issue.severity} Severity
                                           </div>
                                           <h4 className="font-bold text-gray-900 mb-1 pr-16">{issue.issue}</h4>
                                           <p className="text-xs text-gray-600 mb-3">{issue.description}</p>
                                           <div className="pt-3 border-t border-gray-50 flex items-start space-x-2">
                                              <svg className="h-4 w-4 text-indigo-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                              <p className="text-[10px] font-bold text-indigo-600 italic uppercase">Advice: {issue.recommendedAction}</p>
                                           </div>
                                        </div>
                                     ))}
                                  </div>
                               )}

                               <div className="bg-gray-900 text-white p-4 rounded-xl text-[10px] font-medium opacity-80 leading-tight">
                                  ⚠️ DISCLAIMER: This health scan is powered by AI and based on visual data only. It is not a clinical diagnosis. If your animal shows any signs of distress, pain, or illness, consult a licensed veterinarian immediately.
                               </div>
                            </div>
                         )}
                      </div>

                      <div className="space-y-4">
                        <div className="flex items-center justify-between">
                          <h3 className="font-bold text-gray-900">Similar Breeds to Explore</h3>
                        </div>
                        {vizError && (
                          <div className="text-xs text-red-500 bg-red-50 p-2 rounded-lg border border-red-100 flex items-center">
                            <svg className="h-4 w-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            {vizError}
                          </div>
                        )}
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                          {currentResult.similarBreeds.map((breed, idx) => (
                            <div key={idx} className="group bg-white p-4 rounded-2xl border border-gray-100 hover:border-indigo-200 transition-all shadow-sm">
                              <p className="font-bold text-gray-800 mb-3">{breed}</p>
                              <button 
                                onClick={() => handleVisualize(breed)}
                                disabled={isGeneratingImage === breed}
                                className="w-full text-xs font-bold py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 disabled:opacity-50 transition-colors"
                              >
                                {isGeneratingImage === breed ? 'Visualizing...' : 'Visualize with AI'}
                              </button>
                            </div>
                          ))}
                        </div>
                      </div>

                      {/* Fact Grounding Section */}
                      <div className="pt-6 border-t border-gray-100">
                        {!funFacts ? (
                          <button 
                            onClick={handleGetFacts} 
                            disabled={isFetchingFacts}
                            className="flex items-center space-x-2 text-indigo-600 font-bold hover:text-indigo-800 transition-colors"
                          >
                            {isFetchingFacts ? (
                              <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-indigo-600"></div>
                            ) : (
                              <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            )}
                            <span>Search Grounded Fun Facts</span>
                          </button>
                        ) : (
                          <div className="bg-indigo-50/50 p-6 rounded-3xl border border-indigo-100 animate-fade-in">
                            <h4 className="font-bold text-indigo-900 mb-4 flex items-center">
                              <svg className="h-5 w-5 mr-2" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-11a1 1 0 10-2 0v2H7a1 1 0 100 2h2v2a1 1 0 102 0v-2h2a1 1 0 100-2h-2V7z" clipRule="evenodd" /></svg>
                              Grounded Insights
                            </h4>
                            <div className="text-gray-700 text-sm leading-relaxed space-y-4 whitespace-pre-line">
                              {funFacts.text}
                            </div>
                            {funFacts.sources.length > 0 && (
                              <div className="mt-6 flex flex-wrap gap-2">
                                <p className="text-[10px] font-bold text-indigo-400 uppercase w-full">Verified Sources:</p>
                                {funFacts.sources.map((src: any, idx: number) => (
                                  <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-white border border-indigo-100 px-3 py-1 rounded-full text-indigo-600 hover:bg-indigo-600 hover:text-white transition-colors">
                                    {src.title || 'Search Link'}
                                  </a>
                                ))}
                              </div>
                            )}
                          </div>
                        )}
                      </div>

                      <button onClick={() => { setSelectedImage(null); setCurrentResult(null); setFunFacts(null); setHealthAnalysis(null); setVizError(null); }} className="w-full py-4 border-2 border-gray-200 text-gray-500 font-bold rounded-2xl hover:bg-gray-50 transition-all">
                        Discard & New Scan
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </section>
        </div>

        <div className="space-y-6">
          <section className="bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden flex flex-col max-h-[800px]">
            <div className="p-6 border-b border-gray-50 flex justify-between items-center">
              <h2 className="text-lg font-bold text-gray-900">Recent Scans</h2>
              <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">{history.length} Saved</span>
            </div>
            <div className="flex-grow overflow-y-auto p-4 space-y-3 custom-scrollbar">
              {isHistoryLoading ? (
                 <div className="flex flex-col items-center justify-center h-full space-y-2 py-20">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                    <p className="text-xs text-gray-400">Loading catalog...</p>
                 </div>
              ) : history.length === 0 ? (
                <div className="text-center py-20 px-6 opacity-40 grayscale">
                  <svg className="mx-auto h-12 w-12 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                  <p className="mt-4 text-xs font-medium">Your animal catalog will appear here</p>
                </div>
              ) : (
                history.map((item) => (
                  <button key={item.id} onClick={() => selectHistoryItem(item)} className="w-full text-left group p-3 border border-transparent hover:border-indigo-100 rounded-2xl hover:bg-indigo-50/30 transition-all bg-white relative">
                    <div className="flex space-x-3">
                      <img src={item.imageUrl} alt={item.breedName} className="w-14 h-14 object-cover rounded-xl flex-shrink-0 shadow-sm" />
                      <div className="flex-grow min-w-0 flex flex-col justify-center">
                        <div className="flex items-center space-x-2">
                          <p className="font-bold text-gray-900 truncate text-sm">{item.breedName}</p>
                          {item.healthAnalysis && (
                            <span title="Health Report Attached" className="flex-shrink-0">
                               <svg className={`h-3 w-3 ${item.healthAnalysis.isHealthy ? 'text-green-500' : 'text-red-500'}`} fill="currentColor" viewBox="0 0 20 20">
                                  <path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" />
                               </svg>
                            </span>
                          )}
                        </div>
                        <p className="text-[10px] text-gray-400 font-medium">{item.animalType} • {new Date(item.timestamp).toLocaleDateString()}</p>
                      </div>
                    </div>
                  </button>
                ))
              )}
            </div>
          </section>
        </div>
      </div>

      {/* Modal for Generated Image */}
      {generatedImageUrl && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-3xl max-w-lg w-full overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center">
              <h3 className="font-bold text-gray-900">AI Visualized: {generatedImageUrl.breed}</h3>
              <button onClick={() => setGeneratedImageUrl(null)} className="text-gray-400 hover:text-red-500">
                <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <div className="p-2">
              <img src={generatedImageUrl.url} alt={generatedImageUrl.breed} className="w-full h-auto rounded-2xl" />
            </div>
            <div className="p-6 bg-gray-50 flex justify-end">
              <button onClick={() => setGeneratedImageUrl(null)} className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl text-sm hover:bg-indigo-700 transition-colors shadow-lg">Close View</button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { User, BreedResult, HealthAnalysisResponse } from '../types';
import { 
  identifyBreed, 
  getBreedFacts, 
  generateBreedAudio, 
  decodeBase64, 
  decodeAudioData,
  generateSimilarBreedImage,
  detectAnimalDiseases
} from '../services/geminiService';
import { db } from '../services/db';

interface DashboardProps {
  user: User;
}

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [isFetchingFacts, setIsFetchingFacts] = useState(false);
  const [isAnalyzingHealth, setIsAnalyzingHealth] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState<string | null>(null);

  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [currentResult, setCurrentResult] = useState<BreedResult | null>(null);
  const [healthAnalysis, setHealthAnalysis] = useState<HealthAnalysisResponse | null>(null);
  const [funFacts, setFunFacts] = useState<{text: string, sources: any[]} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [vizError, setVizError] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<{breed: string, url: string} | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    return () => { if (audioContextRef.current) audioContextRef.current.close(); };
  }, []);

  const saveScanToDB = async (result: BreedResult) => {
    try {
      await db.saveScan(result);
    } catch (err) {
      console.error("Failed to save scan to DBMS", err);
    }
  };

  const handleIdentify = async () => {
    if (!selectedImage) return;
    setIsUploading(true);
    setError(null);
    setCurrentResult(null);
    setFunFacts(null);
    setHealthAnalysis(null);
    setGeneratedImageUrl(null);
    setVizError(null);

    try {
      const prediction = await identifyBreed(selectedImage);
      const newResult: BreedResult = {
        ...prediction,
        id: Math.random().toString(36).substr(2, 9),
        userId: user.id,
        imageUrl: selectedImage,
        timestamp: new Date().toISOString()
      };
      setCurrentResult(newResult);
      await saveScanToDB(newResult);
    } catch (err: any) {
      setError(err.message || "Failed to identify breed.");
    } finally {
      setIsUploading(false);
    }
  };

  const handleHealthCheck = async () => {
    if (!selectedImage || !currentResult) return;
    setIsAnalyzingHealth(true);
    try {
      const analysis = await detectAnimalDiseases(selectedImage, currentResult.animalType);
      setHealthAnalysis(analysis);

      const updatedResult = { ...currentResult, healthAnalysis: analysis };
      setCurrentResult(updatedResult);
      await saveScanToDB(updatedResult);
    } catch (err: any) {
      console.error(err);
      setError("Health analysis failed. Please try again.");
    } finally {
      setIsAnalyzingHealth(false);
    }
  };

  const handleListen = async () => {
    if (!currentResult || isPlayingAudio) return;
    setIsPlayingAudio(true);
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({
          sampleRate: 24000
        });
      }
      const base64 = await generateBreedAudio(currentResult.description);
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioContextRef.current);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlayingAudio(false);
      source.start();
    } catch (err) {
      console.error(err);
      setIsPlayingAudio(false);
    }
  };

  const handleGetFacts = async () => {
    if (!currentResult) return;
    setIsFetchingFacts(true);
    try {
      const facts = await getBreedFacts(currentResult.breedName);
      setFunFacts(facts);
    } catch (err) {
      console.error(err);
    } finally {
      setIsFetchingFacts(false);
    }
  };

  const handleVisualize = async (breed: string) => {
    setIsGeneratingImage(breed);
    setVizError(null);
    try {
      const url = await generateSimilarBreedImage(breed);
      setGeneratedImageUrl({ breed, url });
    } catch (err: any) {
      console.error(err);
      setVizError(err.message || "Could not generate image for this breed.");
    } finally {
      setIsGeneratingImage(null);
    }
  };

  const resetAll = () => {
    setSelectedImage(null);
    setCurrentResult(null);
    setFunFacts(null);
    setHealthAnalysis(null);
    setVizError(null);
    setGeneratedImageUrl(null);
    setError(null);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10 animate-fade-in text-center">
        <h1 className="text-3xl font-bold text-gray-900 tracking-tight">Breed Discovery & Health Check</h1>
        <p className="text-gray-500 mt-2">Identify animal breeds and analyze visible health status in real-time.</p>
      </div>

      <div className="space-y-8">
        <section className="bg-white rounded-3xl shadow-xl shadow-indigo-50 border border-gray-100 overflow-hidden">
          <div className="p-8">
            {!selectedImage ? (
              <div className="border-2 border-dashed border-indigo-200 bg-indigo-50/30 rounded-2xl p-16 text-center hover:border-indigo-400 transition-all cursor-pointer relative group">
                <input type="file" accept="image/*" onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) {
                    const reader = new FileReader();
                    reader.onloadend = () => setSelectedImage(reader.result as string);
                    reader.readAsDataURL(file);
                  }
                }} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                <div className="space-y-4">
                  <div className="mx-auto w-20 h-20 bg-white text-indigo-600 rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                    <svg className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                    </svg>
                  </div>
                  <div>
                    <p className="text-xl font-bold text-gray-900">Upload Animal Photo</p>
                    <p className="text-sm text-gray-500">Tap to browse or drag & drop</p>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-8">
                <div className="relative group rounded-3xl overflow-hidden shadow-2xl bg-gray-900 aspect-video flex items-center justify-center">
                  <img src={selectedImage} alt="Selected" className="max-h-full max-w-full object-contain" />
                  {!currentResult && !isUploading && (
                    <button onClick={resetAll} className="absolute top-6 right-6 bg-black/50 backdrop-blur-md text-white p-3 rounded-full hover:bg-red-600 transition-all">
                      <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  )}
                </div>

                {error && (
