        >
          <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <span>AI Discovery & Medical</span>
        </button>
        <button 
          onClick={() => setActiveTab('shop')} 
          className={`flex items-center space-x-2 px-8 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'shop' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'text-gray-500 hover:bg-gray-50'}`}
        >
          <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg>
          <span>Marketplace & Collection</span>
        </button>
      </div>

      {activeTab === 'id' ? (
        <div className="space-y-8 animate-fade-in">
          {/* Main ID Section */}
          <section className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
