        <button 
          onClick={() => setActiveTab('id')} 
          className={`flex items-center space-x-3 px-12 py-5 rounded-[2rem] text-sm font-black transition-all duration-500 ${activeTab === 'id' ? 'bg-indigo-600 text-white shadow-2xl shadow-indigo-200 scale-105' : 'text-gray-400 hover:text-indigo-600 hover:bg-white'}`}
        >
          <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <span className="uppercase tracking-widest">AI Discovery</span>
        </button>
        <button 
          onClick={() => setActiveTab('shop')} 
          className={`flex items-center space-x-3 px-12 py-5 rounded-[2rem] text-sm font-black transition-all duration-500 ${activeTab === 'shop' ? 'bg-indigo-600 text-white shadow-2xl shadow-indigo-200 scale-105' : 'text-gray-400 hover:text-indigo-600 hover:bg-white'}`}
        >
          <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg>
          <span className="uppercase tracking-widest">Marketplace</span>
        </button>
      </div>

      {activeTab === 'id' ? (
        <div className="space-y-16 animate-fade-in">
          {/* Main Container */}
          <section className="bg-white rounded-[4rem] shadow-2xl border border-gray-100 overflow-hidden relative">
            <div className="p-10 lg:p-20">
              {!selectedImage ? (
                <div className="border-[6px] border-dashed border-indigo-50 bg-indigo-50/10 rounded-[3.5rem] p-32 text-center hover:border-indigo-200 transition-all cursor-pointer group relative overflow-hidden">
                  <input type="file" accept="image/*" onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const reader = new FileReader();
                      reader.onloadend = () => setSelectedImage(reader.result as string);
                      reader.readAsDataURL(file);
                    }
                  }} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20" />
                  <div className="space-y-8 relative z-10">
                    <div className="mx-auto w-32 h-32 bg-white text-indigo-600 rounded-[2.5rem] flex items-center justify-center shadow-2xl group-hover:scale-110 transition-transform duration-700">
                      <svg className="h-16 w-16" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    </div>
                    <div>
                      <h2 className="text-5xl font-black text-gray-900 tracking-tighter">Capture Species</h2>
                      <p className="text-xl text-gray-500 mt-4 font-medium max-w-lg mx-auto leading-relaxed">Instantly decode identity, medical health, and market value through our AI Neural Engine.</p>
                    </div>
                  </div>
                  <div className="absolute top-0 right-0 -mr-32 -mt-32 h-96 w-96 bg-indigo-100/20 rounded-full blur-[100px]"></div>
                </div>
              ) : (
                <div className="space-y-20">
                  {/* Result Header & Identification Section */}
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-20 items-center">
                    <div className="relative rounded-[3.5rem] overflow-hidden shadow-[0_50px_100px_rgba(0,0,0,0.15)] bg-gray-900 aspect-square flex items-center justify-center group">
                      <img src={selectedImage} alt="Analysis Source" className="h-full w-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                      <button onClick={resetAll} className="absolute top-10 right-10 bg-white/20 backdrop-blur-2xl text-white p-5 rounded-full hover:bg-red-600 transition-all shadow-3xl"><svg className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>

                    {!currentResult ? (
                      <div className="space-y-12">
                        <div className="space-y-6">
                           <h2 className="text-6xl font-black text-gray-900 leading-none tracking-tighter">Asset Prepared</h2>
                           <p className="text-2xl text-gray-500 font-medium leading-relaxed">The AI is primed to perform breed isolation, market indexing, and deep-tissue diagnostics.</p>
                        </div>
                        <button onClick={handleIdentify} disabled={isUploading} className="w-full py-10 bg-indigo-600 text-white font-black rounded-[2.5rem] hover:bg-indigo-700 shadow-3xl shadow-indigo-100 transition-all disabled:opacity-50 text-3xl flex items-center justify-center space-x-6">
                          {isUploading ? <><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-white"></div><span>Analyzing Neural Fields...</span></> : <span>Execute Recognition</span>}
