                      </div>
                    ) : (
                      <div className="space-y-12 animate-fade-in">
                        <div className="space-y-6">
                          <div className="flex items-center space-x-4">
                            <span className="px-6 py-2 bg-indigo-100 text-indigo-700 rounded-2xl text-[12px] font-black uppercase tracking-widest">{currentResult.animalType}</span>
                            <span className="px-6 py-2 bg-green-100 text-green-700 rounded-2xl text-[12px] font-black uppercase tracking-widest">Est. Value: ${currentResult.price.toLocaleString()}</span>
