                                  <div className="p-4 bg-orange-100 text-orange-600 rounded-[1.5rem] mr-6 shadow-sm group-hover:rotate-12 transition-transform"><svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg></div>
                                  Physical Performance Plan
                               </h4>
                               <p className="text-xl text-gray-600 leading-relaxed font-medium italic bg-gray-50/50 p-10 rounded-[2.5rem] border border-gray-100 whitespace-pre-line shadow-inner">{currentResult.exercisePlan}</p>
                            </div>
                         </div>
                      </section>

                      {/* Similar Breeds Visualizer */}
                      <section className="space-y-12">
                         <div className="flex items-center justify-between">
                            <h3 className="text-5xl font-black text-gray-900 tracking-tighter">Species Relatives</h3>
                            <button onClick={handleGetFacts} className="px-10 py-4 bg-indigo-50 text-indigo-600 font-black rounded-2xl hover:bg-indigo-100 transition-all text-sm uppercase tracking-widest shadow-sm">Ground Insights</button>
                         </div>
                         <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-12">
                            {currentResult.similarBreeds.map((breed) => (
                               <div key={breed} className="bg-white rounded-[3.5rem] border border-gray-100 shadow-2xl overflow-hidden group hover:-translate-y-6 transition-all duration-700 hover:shadow-indigo-100/50">
                                  <div className="h-72 bg-gray-900 relative flex items-center justify-center">
                                     {similarBreedImages[breed] ? (
                                        <img src={similarBreedImages[breed]} alt={breed} className="w-full h-full object-cover opacity-90 group-hover:scale-110 transition-transform duration-1000" />
                                     ) : (
                                        <div className="text-center p-10">
                                           <button 
                                             onClick={() => handleVisualizeBreed(breed)}
                                             disabled={loadingSimilarBreed === breed}
                                             className="px-10 py-5 bg-indigo-600 text-white text-xs font-black rounded-[1.5rem] hover:bg-indigo-700 transition-all shadow-2xl"
                                           >
                                              {loadingSimilarBreed === breed ? "Visualizing Neural Stream..." : "AI Visual Preview"}
                                           </button>
                                        </div>
                                     )}
                                     <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent"></div>
                                     <p className="absolute bottom-10 left-10 text-white font-black text-3xl tracking-tighter">{breed}</p>
                                  </div>
                               </div>
                            ))}
                         </div>
                      </section>

                      {/* Final Marketplace CTA */}
                      <div className="flex flex-col xl:flex-row gap-10">
                        {!currentResult.isPurchased ? (
                           <button onClick={handlePurchase} className="flex-grow py-12 bg-indigo-600 text-white text-3xl font-black rounded-[3rem] hover:bg-indigo-700 shadow-[0_40px_100px_rgba(79,70,229,0.3)] transition-all transform hover:-translate-y-2 flex items-center justify-center space-x-8 px-20">
                              <svg className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" /></svg>
                              <span>Acquire to Collection • ${currentResult.price.toLocaleString()}</span>
                           </button>
                        ) : (
                           <div className="flex-grow py-12 bg-indigo-50 border-[6px] border-white text-indigo-700 font-black rounded-[3rem] shadow-2xl flex items-center justify-center space-x-8">
                              <svg className="h-12 w-12" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                              <span className="text-4xl tracking-tighter uppercase">Secured Ownership</span>
                           </div>
                        )}
                        <button onClick={resetAll} className="px-20 py-12 border-4 border-gray-100 text-gray-400 font-black text-sm uppercase tracking-[0.4em] rounded-[3rem] hover:bg-gray-50 transition-all">Reset Scan</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </section>
        </div>
      ) : (
        /* MARKETPLACE MODULE */
        <div className="space-y-20 animate-fade-in">
           <div className="text-center space-y-6">
              <h2 className="text-7xl font-black text-gray-900 tracking-tighter">Ownership Marketplace</h2>
              <p className="text-2xl text-gray-500 font-medium max-w-3xl mx-auto">Manage your species assets, process exchanges, and verify biological security signatures.</p>
           </div>

           {shoppingCart.length === 0 ? (
              <div className="bg-white rounded-[5rem] p-48 text-center border-[6px] border-dashed border-gray-50 shadow-3xl flex flex-col items-center group overflow-hidden relative">
                 <div className="h-40 w-40 bg-indigo-50 rounded-[3rem] flex items-center justify-center text-indigo-200 mb-12 transition-transform group-hover:scale-110 relative z-10"><svg className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg></div>
                 <p className="font-black text-gray-400 uppercase tracking-[0.6em] text-sm relative z-10">Portfolio Void</p>
                 <button onClick={() => setActiveTab('id')} className="mt-16 px-20 py-8 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-3xl hover:bg-indigo-700 transition-all text-xl relative z-10">Execute First Acquisition</button>
                 <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-indigo-50/5 to-transparent"></div>
              </div>
           ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-16">
                 {shoppingCart.map((item) => (
                    <div key={item.id} className="bg-white rounded-[4rem] overflow-hidden shadow-3xl border border-gray-100 flex flex-col group hover:-translate-y-6 transition-all duration-700 hover:shadow-indigo-100/60">
                       <div className="h-80 relative bg-gray-900 overflow-hidden">
                          <img src={item.imageUrl} alt={item.breedName} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[2s] opacity-90" />
                          <div className="absolute top-10 left-10 bg-white/95 backdrop-blur-3xl shadow-2xl px-8 py-3 rounded-full text-[12px] font-black text-indigo-600 uppercase tracking-widest border border-white/50">Asset Verified</div>
                          <div className="absolute bottom-10 right-10 bg-green-600 text-white px-10 py-4 rounded-3xl text-lg font-black shadow-3xl ring-[16px] ring-white/10 tracking-tight">${item.price.toLocaleString()}</div>
                       </div>
                       <div className="p-14 flex-grow">
                          <h3 className="font-black text-gray-900 text-4xl mb-4 tracking-tighter">{item.breedName}</h3>
                          <p className="text-[13px] text-gray-400 font-black uppercase mb-12 tracking-[0.3em]">{item.animalType} • {item.lifeExpectancy} Bio-Span</p>

                          <div className="grid grid-cols-2 gap-8 mb-12">
                             <div className="p-6 bg-gray-50 rounded-[2.5rem] border border-gray-100 text-center shadow-inner">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Status</p>
                                <p className="text-lg font-black text-indigo-600">Active Sync</p>
                             </div>
                             <div className="p-6 bg-gray-50 rounded-[2.5rem] border border-gray-100 text-center shadow-inner">
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Signature</p>
                                <p className="text-lg font-black text-gray-900">#{item.id.toUpperCase().slice(0, 6)}</p>
                             </div>
                          </div>

                          <div className="flex flex-wrap gap-3">
                             {item.uses.map(u => <span key={u} className="px-5 py-2 bg-indigo-50 text-indigo-600 text-[11px] font-black rounded-2xl uppercase tracking-tighter">{u}</span>)}
                          </div>
                       </div>
                       <div className="p-10 bg-gray-50/50 border-t border-gray-100 grid grid-cols-2 gap-8">
                          <button onClick={() => handleExchange(item.breedName)} className="py-6 bg-white text-gray-800 text-[11px] font-black rounded-[2rem] border border-gray-200 hover:bg-gray-100 transition-all uppercase tracking-widest shadow-md">Sync Swap</button>
                          <button onClick={() => handleReturn(item.id)} className="py-6 bg-white text-red-600 text-[11px] font-black rounded-[2rem] border border-red-100 hover:bg-red-50 transition-all uppercase tracking-widest shadow-md">Liquidate</button>
                       </div>
                    </div>
                 ))}
              </div>
           )}

           <div className="bg-gradient-to-br from-indigo-950 to-black text-white p-24 rounded-[5rem] shadow-[0_60px_120px_-20px_rgba(0,0,0,0.4)] relative overflow-hidden group">
              <div className="relative z-10 flex flex-col xl:flex-row items-center justify-between gap-20">
                 <div className="max-w-4xl text-center xl:text-left space-y-10">
                    <h3 className="text-6xl font-black leading-none tracking-tighter">Professional Ownership Protocols</h3>
                    <p className="text-indigo-200 leading-relaxed font-medium text-2xl">Every asset acquired through our neural engine includes biological monitoring, genetic heritage mapping, and lifetime care guidelines synthesized from the latest veterinary intelligence.</p>
                 </div>
                 <div className="flex flex-wrap justify-center gap-12">
                    <div className="p-12 bg-white/5 backdrop-blur-3xl rounded-[4rem] text-center border border-white/10 w-56 transition-transform hover:scale-110">
                       <p className="text-6xl font-black mb-2 tracking-tighter">0%</p>
                       <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-60">Buyback Fee</p>
                    </div>
                    <div className="p-12 bg-indigo-600/30 backdrop-blur-3xl rounded-[4rem] text-center border border-white/10 w-56 transition-transform hover:scale-110">
                       <p className="text-6xl font-black mb-2 tracking-tighter">24h</p>
                       <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-60">Swap Window</p>
                    </div>
                 </div>
              </div>
              <div className="absolute top-0 right-0 -mr-80 -mt-80 h-[800px] w-[800px] bg-indigo-500/10 rounded-full blur-[180px]"></div>
              <div className="absolute bottom-0 left-0 -ml-80 -mb-80 h-[800px] w-[800px] bg-indigo-800/30 rounded-full blur-[180px]"></div>
           </div>
        </div>
      )}

      <style>{`
        .animate-fade-in { animation: fadeIn 1s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(60px); } to { opacity: 1; transform: translateY(0); } }
        .shadow-3xl { filter: drop-shadow(0 45px 65px rgba(0, 0, 0, 0.1)); }
      `}</style>
