import { GoogleGenAI, Type, Modality } from "@google/genai";
import { PredictionResponse, HealthAnalysisResponse } from "../types";

const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY not found in environment. Please ensure it is configured.");
  }
  return new GoogleGenAI({ apiKey });
};

export const identifyBreed = async (base64Image: string): Promise<PredictionResponse> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        {
          text: "Identify the animal in this image. Provide: animal type, breed name, confidence (0-100), short descriptive paragraph (3-4 sentences), 3 similar breeds, estimated market price in USD, primary uses (e.g. companionship, guard, farm), life expectancy (e.g. 10-15 years), a structured daily diet routine, and an exercise plan. Use current global market estimates for pricing.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          animalType: { type: Type.STRING },
          breedName: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          description: { type: Type.STRING },
          similarBreeds: { type: Type.ARRAY, items: { type: Type.STRING } },
          price: { type: Type.NUMBER },
          uses: { type: Type.ARRAY, items: { type: Type.STRING } },
          lifeExpectancy: { type: Type.STRING },
          dietRoutine: { type: Type.STRING },
          exercisePlan: { type: Type.STRING },
        },
        required: ["animalType", "breedName", "confidence", "description", "similarBreeds", "price", "uses", "lifeExpectancy", "dietRoutine", "exercisePlan"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI Neural Network returned an empty response.");
  return JSON.parse(text);
};

export const detectAnimalDiseases = async (base64Image: string, animalType: string): Promise<HealthAnalysisResponse> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        {
          text: `Perform a deep clinical visual diagnostic for this ${animalType}. Analyze tissue quality, visible pathologies, dental alignment, and anatomical symmetry. Identify any specific diseases, infections, or nutritional deficiencies visible. For each issue, provide a description and a specific professional recommendation. Return the results in the specified JSON format.`,
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          potentialIssues: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                issue: { type: Type.STRING },
                severity: { type: Type.STRING, description: "Low, Medium, or High" },
                description: { type: Type.STRING },
                recommendedAction: { type: Type.STRING }
              },
              required: ["issue", "severity", "description", "recommendedAction"]
            }
          },
          summary: { type: Type.STRING },
          isHealthy: { type: Type.BOOLEAN }
        },
        required: ["potentialIssues", "summary", "isHealthy"]
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Health diagnostic engine failed.");
  return JSON.parse(text);
};

export const generateBreedAudio = async (text: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Narrate the following animal care profile in a professional, warm veterinary voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });
  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Audio generation failed.");
  return base64Audio;
};

export const getBreedFacts = async (breed: string): Promise<{text: string, sources: any[]}> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Tell me 3 fascinating, professional, and unique facts about the ${breed} animal breed. Include details about its history and special abilities.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });
  return {
    text: response.text || "No facts found.",
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
  };
};

export const generateSimilarBreedImage = async (breed: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: `A high-quality, professional portrait of a ${breed} in a clean, aesthetic studio setting. Studio lighting, sharp focus.`,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Image generation failed.");
};

export const decodeBase64 = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

